INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "人助け、応援", "ヒヨリ", 8, 155, "A", 27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", 2, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, "東山奈央", 16, "獣人族", 100101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "料理、人間観察", "ユイ", 4, 158, "O", 5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", 2, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, "種田梨沙", 17, "ヒューマン", 100201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書、乗馬、お茶", "レイ", 1, 163, "B", 12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", 2, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, "早見沙織", 18, "魔族", 100301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "いたずら、探検", "ミソギ", 8, 128, "O", 10, "探検好きのイタズラっ子", "リトルリリカル", 5, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, "諸星すみれ", 9, "ヒューマン", 100401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ヒーローごっこ", "マツリ", 11, 146, "O", 25, "ヒーローに憧れる騎士見習いの少女", "王宮騎士団（NIGHTMARE）", 8, "？？？", 40, "下田麻美", 12, "獣人族", 100501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "サックス", "アカリ", 11, 150, "O", 22, "甘え上手なみんなの人気者", "悪魔偽王国軍（ディアボロス）", 7, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 42, "浅倉杏美", 13, "魔族", 100601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "プリンを食べること", "ミヤコ", 1, 130, "B", 23, "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", 7, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, "雨宮天", 14, "魔族", 100701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "鏡で自分を見ること", "ユキ", 10, 150, "AB", 10, "ボクは誰よりも美しい", "ヴァイスフリューゲル　ランドソル支部", 15, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, "大空直美", 14, "エルフ", 100801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "小説執筆", "アンナ", 7, 159, "A", 5, "前世を信じる中二病患者、「疾風の冥姫」", "トワイライトキャラバン", 13, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 45, "髙野麻美", 17, "魔族", 100901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "空想、ぬいぐるみ集め", "マホ", 9, 155, "O", 22, "マホマホ王国のプリンセス", "自警団（カォン）", 10, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 42, "内田真礼", 16, "獣人族", 101001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お裁縫", "リノ", 8, 156, "A", 25, "人懐っこくてマシンガントークな妹系少女", "ラビリンス", 3, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 44, "阿澄佳奈", 15, "ヒューマン", 101101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "妹と遊ぶこと、二度寝、昼寝、早寝", "ハツネ", 12, 156, "A", 24, "みんなのために超能力を使う眠り姫", "フォレスティエ", 6, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 46, "大橋彩香", 17, "エルフ", 101201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書、魔法", "ナナカ", 8, 166, "O", 21, "オタク全開な魔法少女", "トワイライトキャラバン", 13, "", 55, "佳村はるか", 18, "魔族", 101301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書、推理", "カスミ", 11, 152, "AB", 3, "頭脳明晰な美少女名探偵", "自警団（カォン）", 10, "test", 41, "水瀬いのり", 15, "獣人族", 101401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "絵本作り", "ミサト", 9, 165, "O", 5, "母性溢れる優しいみんなの「ミサト先生」", "フォレスティエ", 6, "test", 54, "國府田マリ子", 21, "エルフ", 101501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ファッション", "スズナ", 4, 167, "O", 10, "天真爛漫で人気者のカリスマモデル", "ルーセント学院", 14, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, "上坂すみれ", 17, "魔族", 101601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "踊り、空手", "カオリ", 7, 158, "A", 7, "いつでも「なんくるないさ～」な天然娘", "自警団（カォン）", 10, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, "高森奈津美", 17, "獣人族", 101701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "イオ", 8, 162, "B", 14, "多くの男性を魅了する無垢な女教師", "ルーセント学院", 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 52, "伊藤静", 23, "魔族", 101801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "かわいいもの集め", "ミミ", 4, 117, "O", 3, "お歌もにんじんも、ウサギさんも大好き♪", "リトルリリカル", 5, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 21, "日高里菜", 10, "獣人族", 102001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "観劇、おままごと", "クルミ", 6, 150, "B", 9, "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, "植田佳奈", 12, "ヒューマン", 102101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ゲーム全般", "ヨリ", 11, 150, "O", 22, "人見知りであまのじゃくな女の子", "悪魔偽王国軍（ディアボロス）", 7, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 40, "原紗友里", 13, "魔族", 102201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "屋内でできる遊び", "アヤネ", 5, 148, "B", 10, "ぷうきちといつも一緒！", "サレンディア救護院", 9, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, "芹澤優", 14, "ヒューマン", 102301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ご奉仕", "スズメ", 12, 154, "O", 12, "お嬢さまのためにがんばるドジっ娘メイド", "サレンディア救護院", 9, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, "悠木碧", 15, "ヒューマン", 102501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "あんパン", "リン", 1, 144, "B", 1, "遊びと睡眠が何より大事なぐうたら娘", "牧場（エリザベスパーク）", 11, "test", 42, "小岩井ことり", 17, "獣人族", 102601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "実験、裁縫、料理", "エリコ", 7, 154, "B", 30, "運命の相手に一途すぎる乙女", "トワイライトキャラバン", 13, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, "橋本ちなみ", 16, "魔族", 102701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "経営、お茶会", "サレン", 10, 156, "A", 4, "救護院を経営する優しい庶民派お嬢様", "サレンディア救護院", 9, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 43, "堀江由衣", 17, "エルフ", 102801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "舞台鑑賞、ダンス", "ノゾミ", 1, 157, "B", 24, "歌って踊れる大人気アイドル", "カルミナ", 4, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 40, "日笠陽子", 17, "ヒューマン", 102901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "忍法開発", "ニノン", 8, 163, "O", 31, "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", 15, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, "佐藤聡美", 16, "ヒューマン", 103001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "占い", "シノブ", 12, 157, "AB", 22, "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", 7, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, "大坪由佳", 18, "魔族", 103101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "慈善事業", "アキノ", 3, 157, "AB", 12, "一人前の商人を目指すパワフルお嬢様", "メルクリウス財団", 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 45, "松嵜麗", 18, "ヒューマン", 103201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "漫才", "マヒル", 3, 142, "B", 3, "みんなを笑顔にするお笑い牧場主", "牧場（エリザベスパーク）", 11, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 35, "新田恵海", 20, "ヒューマン", 103301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ウインドーショッピング", "ユカリ", 3, 164, "A", 16, "純情でほっとけない大人の女性", "メルクリウス財団", 12, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 55, "今井麻美", 22, "エルフ", 103401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お勉強", "キョウカ", 2, 118, "A", 2, "礼儀正しくしっかり者のちびっ子優等生", "リトルリリカル", 5, "test", 21, "小倉唯", 8, "エルフ", 103601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "剣術、年長者をからかう", "トモ", 8, 149, "A", 11, "義理堅くてからかい好きな剣術少女", "王宮騎士団（NIGHTMARE）", 8, "test", 43, "茅原実里", 13, "ヒューマン", 103701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書、お散歩", "シオリ", 11, 153, "A", 3, "読書が趣味の病弱少女", "牧場（エリザベスパーク）", 11, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 40, "小清水亜美", 14, "獣人族", 103801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "友達作りのイメトレ", "アオイ", 6, 158, "AB", 6, "「友達」に憧れる、エルフの森の女の子", "フォレスティエ", 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 44, "花澤香菜", 13, "エルフ", 104001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "各種楽器", "チカ", 6, 163, "O", 3, "人々を守るために歌う、唱喚士の少女", "カルミナ", 4, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, "福原綾香", 17, "ヒューマン", 104201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お菓子作り", "マコト", 8, 168, "O", 9, "男勝りで情に厚いワイルド娘", "自警団（カォン）", 10, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 54, "小松未可子", 17, "獣人族", 104301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "世界征服", "イリヤ", 5, 172, "A", 5, "かつては夜を支配した最強の吸血鬼", "悪魔偽王国軍（ディアボロス）", 7, "test", 50, "丹下桜", "??", "魔族", 104401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "小説を読むこと", "クウカ", 11, 157, "AB", 19, "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", 15, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, "長妻樹里", 18, "ヒューマン", 104501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "猫とたわむれること", "タマキ", 3, 158, "AB", 1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", 12, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, "沼倉愛美", 19, "獣人族", 104601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "格闘技、湯浴み", "ジュン", 10, 171, "A", 25, "素顔を見せない冷静沈着な女性騎士", "王宮騎士団（NIGHTMARE）", 8, "？？？", 50, "川澄綾子", 25, "ヒューマン", 104701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "傭兵などのアルバイト", "ミフユ", 11, 163, "O", 11, "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", 12, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, "田所あずさ", 20, "ヒューマン", 104801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "家事全般", "シズル", 10, 168, "O", 24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", 3, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, "生天目仁美", 18, "ヒューマン", 104901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ファッション誌鑑賞、コスメ集め", "ミサキ", 1, 120, "A", 3, "ちょっとおませな恋に恋する女の子", "ルーセント学院", 14, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, "久野美咲", 11, "魔族", 105001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "研究、実験", "ミツキ", 3, 166, "A", 7, "実験が趣味の危険な科学者", "トワイライトキャラバン", 13, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 53, "三石琴乃", 27, "ヒューマン", 105101);
