INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "お菓子屋通い", "モニカ", 7, 140, "A", 28, "見た目も中身もお子ちゃまな異国の軍人", "ヴァイスフリューゲル　ランドソル支部", 15, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 33, "辻あゆみ", 17, "ヒューマン", 105301);
