INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "猫とたわむれること", "タマキ（サマー）", 3, 158, "AB", 1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", 12, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, "沼倉愛美", 19, "獣人族", 107901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "傭兵などのアルバイト", "ミフユ（サマー）", 11, 163, "O", 11, "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", 12, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, "田所あずさ", 20, "ヒューマン", 108001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "占い", "シノブ（ハロウィン）", 12, 157, "AB", 22, "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", 7, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, "大坪由佳", 18, "魔族", 108101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "プリンを食べること", "ミヤコ（ハロウィン）", 1, 130, "B", 23, "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", 7, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, "雨宮天", 14, "魔族", 108201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ファッション誌鑑賞、コスメ集め", "ミサキ（ハロウィン）", 1, 120, "A", 3, "ちょっとおませな恋に恋する女の子", "ルーセント学院", 14, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, "久野美咲", 11, "魔族", 108301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "各種楽器", "チカ（クリスマス）", 6, 163, "O", 3, "人々を守るために歌う、唱喚士の少女", "カルミナ", 4, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, "福原綾香", 17, "ヒューマン", 108401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "観劇、おままごと", "クルミ（クリスマス）", 6, 150, "B", 9, "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, "植田佳奈", 12, "ヒューマン", 108501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "屋内でできる遊び", "アヤネ（クリスマス）", 5, 148, "B", 10, "ぷうきちといつも一緒！", "サレンディア救護院", 9, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, "芹澤優", 14, "ヒューマン", 108601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "人助け、応援", "ヒヨリ（ニューイヤー）", 8, 155, "A", 27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", 2, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, "東山奈央", 16, "獣人族", 108701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "料理、人間観察", "ユイ（ニューイヤー）", 4, 158, "O", 5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", 2, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, "種田梨沙", 17, "ヒューマン", 108801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書、乗馬、お茶", "レイ（ニューイヤー）", 1, 163, "B", 12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", 2, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, "早見沙織", 18, "魔族", 108901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "実験、裁縫、料理", "エリコ（バレンタイン）", 7, 154, "B", 30, "運命の相手に一途すぎる乙女", "トワイライトキャラバン", 13, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, "橋本ちなみ", 16, "魔族", 109001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "家事全般", "シズル（バレンタイン）", 10, 168, "O", 24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", 3, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, "生天目仁美", 18, "ヒューマン", 109101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "読書", "アン", 12, 156, "AB", 1, "英霊と契約を結んだマナリアの天才王女", "？？？", "", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 55, "日笠陽子", 17, "ヒューマン", 109201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "食べること、眠ること", "ルゥ", 2, 144, "O", 4, "マナリア魔法学院の新入生", "？？？", "", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 45, "こやまきみこ", 16, "ヒューマン", 109301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "ピアノ", "グレア", 11, 167, "B", 3, "人を超越した力を有す心優しい竜姫", "？？？", "", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 67, "福原綾香", 17, "半人半竜", 109401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "小説を読むこと", "クウカ（オーエド）", 11, 157, "AB", 19, "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", 15, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, "長妻樹里", 18, "ヒューマン", 109501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (0, "忍法開発", "ニノン（オーエド）", 8, 163, "O", 31, "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", 15, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, "佐藤聡美", 16, "ヒューマン", 109601);
